#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    int c;
    cin >> c;
    int m;
    cin >> m;
    vector<int> stalls(m);
    for(int i = 0; i < m; i++) cin >> stalls[i];
    sort(stalls.begin(), stalls.end());

    auto can_place_cows = [&](int min_distance) {
        int placed_cows = 1;
        int last_cow_position = stalls[0];
        for(int i = 1; i < m; i++) {
            if(stalls[i] - last_cow_position >= min_distance) {
                placed_cows += 1;
                last_cow_position = stalls[i];
            }
        }
        return placed_cows >= c;
    };

    int low = 1;
    int high = stalls.back() - stalls[0];
    while(low <= high) {
        int mid = (low + high) / 2;
        if(can_place_cows(mid)) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    cout << high << endl;
    return 0;
}
